sql:
SELECT AVG(access_id) AS average_access_id
FROM access_logs
WHERE dataset_id = 0;

SELECT COUNT(*) AS total_grain_datasets 
FROM grain_datasets 
WHERE quality_score > (SELECT AVG(quality_score) FROM grain_datasets);

SELECT dataset_id, AVG(perimeter) AS average_perimeter
FROM grain_datasets
GROUP BY dataset_id;

external_knowledge:
- "Above-average datasets" refers to datasets with a quality score greater than 5.0;
- "Typical measurement values" refers to the average value of the attribute for each grain;
- "How often they are accessed" denotes the number of access events per grain type.

sql:
SELECT AVG(value) AS average_kernel_length
FROM grain_values
WHERE attribute_id = (SELECT attribute_id FROM grain_attributes WHERE attribute_name = 'kernel_length');

SELECT COUNT(*) AS active_grain_types
FROM grain_types
WHERE status = 'active';
